console.log('1 — sync');  // → Call Stack

setTimeout(() => {
  console.log('4 — setTimeout (macrotask)');
}, 0);

Promise.resolve()
  .then(() => console.log('3 — Promise .then (microtask)'));

console.log('2 — sync');  // → Call Stack

// Output order:
// 1 — sync
// 2 — sync
// 3 — Promise .then (microtask)   ← microtask before macrotask!
// 4 — setTimeout (macrotask)

// Why? Event loop drains the microtask queue
// completely before running any macrotask.
